  	//-------------------------------------------------------------------------
  	// 금액계산 가수금액 입력시
 	//-------------------------------------------------------------------------
 	scwin.f_setAmtSusRecvSellAmtTot = function(){
		scwin.f_setMethAmt();

 		var amt = scwin.sumAmtAll-scwin.pldgAmt; 	

 		scwin.susRecvSellAmt = amt<=0 ? 0:amt-scwin.susRecvSellAmtTot>=0 ? scwin.susRecvSellAmtTot:amt;
 		scwin.susRecvSellRtnDrAmt = scwin.susRecvSellAmtTot - scwin.susRecvSellAmt;
 		scwin.maxSusRtnAmt = scwin.susRecvSellAmtTot - scwin.susRecvSellAmt;
 		scwin.sumAmtDtl = scwin.cashSellAmt+scwin.susRecvSellAmtTot+scwin.pldgAmt;

 		scwin.cashRtnAmt = scwin.initamtGrtRtnDrAmt + scwin.susRecvSellRtnDrAmt;

 		ed_susRecvSellRtnDrAmt.setValue(scwin.susRecvSellRtnDrAmt); 
 		ed_susRecvSellAmt.setValue(scwin.susRecvSellAmt);
 		ed_sumAmtAll.setValue(scwin.sumAmtAll); 			
 		ed_initamtGrtDrAmt.setValue(scwin.initamtGrtDrAmt); 	
 		ed_egain.setValue(scwin.egain); 				
 		ed_sumAmtDtl.setValue(scwin.sumAmtDtl); 			
 		ed_initamtGrtRtnDrAmt.setValue(scwin.initamtGrtRtnDrAmt); 	
 		ed_cashRtnAmt.setValue($c.gus.cfInsertComma(scwin.cashRtnAmt)); 			
 		ed_maxSusRtnAmt.setValue(scwin.maxSusRtnAmt); 		
 		ed_maxInitRtnAmt.setValue(scwin.maxInitRtnAmt);

	 	tbx_sumAmtDtl.setValue($c.gus.cfInsertComma(scwin.sumAmtDtl));
	 	ed_cashSellAmtCon.setValue(scwin.sumAmtAll-scwin.susRecvSellRtnDrAmt-scwin.susRecvSellAmt-scwin.pldgAmt+scwin.egain+scwin.cashRtnAmt);
 	};

  	//-------------------------------------------------------------------------
  	// 금액계산 전도현금 입력시
 	//-------------------------------------------------------------------------
 	scwin.f_setAmtCashRtnAmt = function(){
		scwin.f_setMethAmt();

 		var amt = scwin.maxSusRtnAmt+scwin.maxInitRtnAmt; 
 		if(scwin.cashRtnAmt > amt){
 			$c.gus.cfAlertMsg("환불금액 입력한도 초과입니다.");
 			scwin.cashRtnAmt = scwin.susRecvSellRtnDrAmt+scwin.initamtGrtRtnDrAmt;
 		}
 		if(scwin.cashRtnAmt < scwin.susRecvSellRtnDrAmt){
 			$c.gus.cfAlertMsg("환불금액은 가수금매출환불차변금액 보다 작을 수 없습니다.");
 			scwin.cashRtnAmt = scwin.susRecvSellRtnDrAmt+scwin.initamtGrtRtnDrAmt;
 		}	
 		scwin.egain = amt - scwin.cashRtnAmt;
 		scwin.initamtGrtRtnDrAmt = scwin.cashRtnAmt - scwin.susRecvSellRtnDrAmt;

 		ed_susRecvSellRtnDrAmt.setValue( scwin.susRecvSellRtnDrAmt); 
 		ed_susRecvSellAmt.setValue(scwin.susRecvSellAmt);
 		ed_sumAmtAll.setValue(scwin.sumAmtAll); 			
 		ed_initamtGrtDrAmt.setValue(scwin.initamtGrtDrAmt); 	
 		ed_egain.setValue(scwin.egain); 				
 		ed_sumAmtDtl.setValue(scwin.sumAmtDtl); 			
 		ed_initamtGrtRtnDrAmt.setValue(scwin.initamtGrtRtnDrAmt); 	
 		ed_cashRtnAmt.setValue($c.gus.cfInsertComma(scwin.cashRtnAmt)); 			
 		ed_maxSusRtnAmt.setValue(scwin.maxSusRtnAmt); 		
 		ed_maxInitRtnAmt.setValue(scwin.maxInitRtnAmt);

	 	tbx_egain.setValue($c.gus.cfInsertComma(scwin.egain));
	 	ed_cashSellAmtCon.setValue(scwin.sumAmtAll-scwin.susRecvSellRtnDrAmt-scwin.susRecvSellAmt-scwin.pldgAmt+scwin.egain+scwin.cashRtnAmt);
 	};

  	//-------------------------------------------------------------------------
  	// 금액계산 입력시 검증
 	//-------------------------------------------------------------------------
 	scwin.f_chkAmt = function(){
		scwin.f_setMethAmt();
 		if(scwin.sumAmtAll == scwin.cashSellAmt+scwin.susRecvSellRtnDrAmt+scwin.susRecvSellAmt+scwin.pldgAmt-scwin.egain-((scwin.initamtGrtRtnDrAmt+scwin.susRecvSellRtnDrAmt+scwin.cashRtnAmt)/2)){
 			return true;
 		}else{
 			return false;
 		}
 	};

  	//-------------------------------------------------------------------------
  	// 금액계산
 	//-------------------------------------------------------------------------
 	scwin.f_setMethAmt = function(){
 		scwin.sumAmtAll 			= $c.gus.cfIsNull(ed_sumAmtAll.getValue())?0:ed_sumAmtAll.getValue().replaceAll(",","");
 		scwin.cashSellAmt 		    = $c.gus.cfIsNull(ed_cashSellAmt.getValue())?0:ed_cashSellAmt.getValue().replaceAll(",","");
 		scwin.susRecvSellRtnDrAmt   = $c.gus.cfIsNull(ed_susRecvSellRtnDrAmt.getValue())?0:ed_susRecvSellRtnDrAmt.getValue().replaceAll(",","");
 		scwin.susRecvSellAmt 		= $c.gus.cfIsNull(ed_susRecvSellAmt.getValue())?0:ed_susRecvSellAmt.getValue().replaceAll(",","");
 		scwin.susRecvSellAmtTot 	= $c.gus.cfIsNull(ed_susRecvSellAmtTot.getValue())?0:ed_susRecvSellAmtTot.getValue().replaceAll(",","");
 		scwin.pldgAmt 			    = $c.gus.cfIsNull(ed_pldgAmt.getValue())?0:ed_pldgAmt.getValue().replaceAll(",","");
 		scwin.initamtGrtDrAmt 	    = $c.gus.cfIsNull(ed_initamtGrtDrAmt.getValue())?0:ed_initamtGrtDrAmt.getValue().replaceAll(",","");
 		scwin.egain 				= $c.gus.cfIsNull(ed_egain.getValue())?0:ed_egain.getValue().replaceAll(",","");
 		scwin.sumAmtDtl 			= $c.gus.cfIsNull(ed_sumAmtDtl.getValue())?0:ed_sumAmtDtl.getValue().replaceAll(",","");
 		scwin.initamtGrtRtnDrAmt 	= $c.gus.cfIsNull(ed_initamtGrtRtnDrAmt.getValue())?0:ed_initamtGrtRtnDrAmt.getValue().replaceAll(",","");
 		scwin.cashRtnAmt 			= $c.gus.cfIsNull(ed_cashRtnAmt.getValue())?0:ed_cashRtnAmt.getValue().replaceAll(",","");
 		scwin.maxSusRtnAmt 		    = $c.gus.cfIsNull(ed_maxSusRtnAmt.getValue())?0:ed_maxSusRtnAmt.getValue().replaceAll(",","");
 		scwin.maxInitRtnAmt 		= $c.gus.cfIsNull(ed_maxInitRtnAmt.getValue())?0:ed_maxInitRtnAmt.getValue().replaceAll(",","");

 		scwin.sumAmtAll 			= Number(scwin.sumAmtAll);
 		scwin.cashSellAmt 		    = Number(scwin.cashSellAmt);
 		scwin.susRecvSellRtnDrAmt   = Number(scwin.susRecvSellRtnDrAmt);
 		scwin.susRecvSellAmt 		= Number(scwin.susRecvSellAmt);
 		scwin.susRecvSellAmtTot 	= Number(scwin.susRecvSellAmtTot);
 		scwin.pldgAmt 			    = Number(scwin.pldgAmt);
 		scwin.initamtGrtDrAmt 	    = Number(scwin.initamtGrtDrAmt);
 		scwin.egain 				= Number(scwin.egain);
 		scwin.sumAmtDtl 			= Number(scwin.sumAmtDtl);
 		scwin.initamtGrtRtnDrAmt 	= Number(scwin.initamtGrtRtnDrAmt);
 		scwin.cashRtnAmt 			= Number(scwin.cashRtnAmt);
 		scwin.maxSusRtnAmt 		    = Number(scwin.maxSusRtnAmt);
 		scwin.maxInitRtnAmt 		= Number(scwin.maxInitRtnAmt);
 	};

scwin.sbm_RetrieveSellingInfo_submitdone = function (e) {
	if(ds_sellingEvidence.getRowCount() > 0){
		$c.gus.cfDisableBtnOnly([btn_del]);
		$c.gus.cfEnableBtnOnly([btn_save]);
	}else{
		$c.gus.cfDisableBtnOnly([btn_save]);
		$c.gus.cfDisableBtnOnly([btn_del]);
	}

	ica_slipDt.setValue(scwin.strToDate);
	ica_spplyDt.setValue(scwin.strToDate);

	var spplyAmt = 0;
	var spplyAmtFcrc = 0;
	var vatAmt = 0;
	var totAmt = 0;
	var fireInsrRateAmt = 0;
	for(var i=0;i<ds_certiDetailList.getRowCount();i++){
		if(ds_certiDetailList.getCellData(i, "sellYn") == 1){
			spplyAmt        += $c.gus.cfIsNull(ds_certiDetailList.getCellData(i, "spplyAmt")) ? 0 : parseInt(ds_certiDetailList.getCellData(i, "spplyAmt"));
			spplyAmtFcrc    += $c.gus.cfIsNull(ds_certiDetailList.getCellData(i, "spplyAmtFcrc")) ? 0 : parseInt(ds_certiDetailList.getCellData(i, "spplyAmtFcrc"));
			vatAmt        	+= $c.gus.cfIsNull(ds_certiDetailList.getCellData(i, "vatAmt")) ? 0 : parseInt(ds_certiDetailList.getCellData(i, "vatAmt"));
			totAmt        	+= $c.gus.cfIsNull(ds_certiDetailList.getCellData(i, "totAmt")) ? 0 : parseInt(ds_certiDetailList.getCellData(i, "totAmt"));
		}else if (ds_certiDetailList.getCellData(i, "sellItemCd") == "0255"){
			fireInsrRateAmt	+= $c.gus.cfIsNull(ds_certiDetailList.getCellData(i, "spplyAmt")) ? 0 : parseInt(ds_certiDetailList.getCellData(i, "spplyAmt"));
		}
	}
	tbx_spplyAmt.setValue($c.gus.cfInsertComma(spplyAmt));
	tbx_spplyAmtFcrc.setValue($c.gus.cfInsertComma(spplyAmtFcrc));
	tbx_vatAmt.setValue($c.gus.cfInsertComma(vatAmt));
	tbx_sumAmt.setValue($c.gus.cfInsertComma(totAmt));
	tbx_fireInsrRateAmt.setValue($c.gus.cfInsertComma(fireInsrRateAmt));
	ed_spplyAmt.setValue(spplyAmt);
	ed_spplyAmtFcrc.setValue(spplyAmtFcrc);
	ed_vatAmt.setValue(vatAmt);
	ed_sumAmt.setValue(totAmt);
	ed_fireInsrRateAmt.setValue(fireInsrRateAmt);
	ed_sumAmtAll.setValue(totAmt + fireInsrRateAmt);

	scwin.f_setAmtFirst();
	scwin.saveflag = "N";
};

